'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import { Mail, Lock, AlertCircle } from 'lucide-react'
import { branchAuthService } from '@/lib/services/branchAuthService'
import { formatUserError } from '@/lib/errors'
import { mockBranches } from '@/lib/mock-data'
import { DEMO_MODE } from '@/lib/config'

const DEMO_ACCOUNTS = mockBranches
  .filter(b => b.managerEmail && b.managerId)
  .map(b => ({
    name: b.managerName ?? '',
    email: b.managerEmail ?? '',
    branchName: b.name,
  }))

export default function BranchLoginPage() {
  const router = useRouter()
  const [email, setEmail]       = useState('')
  const [password, setPassword] = useState('')
  const [error, setError]       = useState('')
  const [loading, setLoading]   = useState(false)

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    setError('')
    setLoading(true)
    try {
      await branchAuthService.login(email, password)
      router.replace('/branch')
    } catch (err: unknown) {
      setError(formatUserError(err, 'Connexion impossible. Vérifiez votre email et votre mot de passe.'))
    } finally {
      setLoading(false)
    }
  }

  return (
    <div className="min-h-screen flex">
      {/* Left panel — orange brand */}
      <div className="hidden lg:flex lg:w-2/5 bg-orange-500 flex-col justify-between p-10">
        <div className="flex items-center gap-3">
          <div className="w-9 h-9 rounded-xl bg-white/20 flex items-center justify-center">
            <span className="text-white font-bold text-sm">TA</span>
          </div>
          <div>
            <p className="text-white font-semibold text-sm">TiiBnTick Agency</p>
            <p className="text-orange-100 text-xs">Rapid Express Douala</p>
          </div>
        </div>

        <div>
          <h1 className="text-3xl font-bold text-white leading-tight mb-4">
            Espace<br />Responsable d'Antenne
          </h1>
          <p className="text-orange-100 text-sm leading-relaxed">
            Gérez votre antenne, suivez vos missions, votre personnel et votre flotte — en toute autonomie.
          </p>
        </div>

        <div className="space-y-3">
          {DEMO_ACCOUNTS.map(a => (
            <div key={a.email} className="bg-white/10 rounded-xl px-4 py-3">
              <p className="text-white text-xs font-semibold">{a.name}</p>
              <p className="text-orange-100 text-[11px]">{a.branchName}</p>
              <p className="text-orange-200 text-[10px] font-mono mt-0.5">{a.email}</p>
            </div>
          ))}
          {DEMO_MODE && (
            <p className="text-orange-200 text-[11px] text-center pt-1">
              Mot de passe demo : <span className="font-mono font-bold text-white">branch1234</span>
            </p>
          )}
        </div>
      </div>

      {/* Right panel — form */}
      <div className="flex-1 flex items-center justify-center px-6 py-12 bg-white">
        <div className="w-full max-w-sm">
          <div className="mb-8">
            <h2 className="text-2xl font-bold text-gray-900">Connexion</h2>
            <p className="text-sm text-gray-500 mt-1">Accédez à votre espace antenne</p>
          </div>

          <form onSubmit={handleSubmit} className="space-y-4">
            {/* Email */}
            <div>
              <label className="block text-xs font-semibold text-gray-600 mb-1.5">
                Adresse email
              </label>
              <div className="relative">
                <Mail size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                <input
                  type="email"
                  value={email}
                  onChange={e => setEmail(e.target.value)}
                  placeholder="prenom.nom@rapidexpress.cm"
                  required
                  className="w-full pl-9 pr-4 py-2.5 text-sm border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-orange-400 focus:border-transparent placeholder:text-gray-300 transition"
                />
              </div>
            </div>

            {/* Password */}
            <div>
              <label className="block text-xs font-semibold text-gray-600 mb-1.5">
                Mot de passe
              </label>
              <div className="relative">
                <Lock size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                <input
                  type="password"
                  value={password}
                  onChange={e => setPassword(e.target.value)}
                  placeholder="••••••••"
                  required
                  className="w-full pl-9 pr-4 py-2.5 text-sm border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-orange-400 focus:border-transparent placeholder:text-gray-300 transition"
                />
              </div>
            </div>

            {/* Demo quick-fill (mobile only) */}
            {DEMO_MODE && (
              <div className="lg:hidden space-y-2 pt-1">
                <p className="text-[11px] text-gray-400 font-medium uppercase tracking-wide">Comptes demo</p>
                {DEMO_ACCOUNTS.map(a => (
                  <button
                    key={a.email}
                    type="button"
                    onClick={() => { setEmail(a.email); setPassword('branch1234') }}
                    className="w-full flex items-center justify-between bg-orange-50 border border-orange-100 rounded-xl px-3 py-2 text-left"
                  >
                    <div>
                      <p className="text-xs font-semibold text-gray-700">{a.name}</p>
                      <p className="text-[10px] text-gray-400">{a.branchName}</p>
                    </div>
                    <span className="text-[10px] font-semibold text-orange-500 bg-orange-100 px-2 py-0.5 rounded-full">
                      Utiliser
                    </span>
                  </button>
                ))}
              </div>
            )}

            {/* Error */}
            {error && (
              <div className="flex items-center gap-2 bg-red-50 border border-red-200 rounded-lg px-3 py-2.5">
                <AlertCircle size={14} className="text-red-500 flex-shrink-0" />
                <p className="text-xs text-red-600">{error}</p>
              </div>
            )}

            <button
              type="submit"
              disabled={loading}
              className="w-full py-2.5 bg-orange-500 hover:bg-orange-600 disabled:bg-orange-300 text-white text-sm font-semibold rounded-lg transition-colors"
            >
              {loading ? 'Connexion…' : 'Se connecter'}
            </button>
          </form>

          <p className="mt-6 text-center text-xs text-gray-400">
            Pas un responsable d'antenne ?{' '}
            <a href="/login" className="text-orange-500 hover:underline font-medium">
              Portail Agence
            </a>
          </p>
        </div>
      </div>
    </div>
  )
}
